<script setup lang="ts">
const reports=useAttendanceReports(); const feedback=useUiFeedback(); const loading=ref(false); const now=new Date(); const year=ref(now.getFullYear()); const month=ref(now.getMonth()+1); const data=ref<any|null>(null)
async function refresh(){ loading.value=true; try{ data.value=await reports.monthly({year:year.value, month:month.value}) }catch(e:any){ feedback.fromError('Monthly attendance failed',e) } finally{ loading.value=false } }
async function recalc(){ await reports.recalculate({year:year.value, month:month.value}); await refresh() }
onMounted(refresh)
</script>
<template><AppShell title="Monthly Attendance" @refresh="refresh"><section class="space-y-5"><UiModulePageHeader title="Monthly Attendance" description="Computed attendance status by employee/day. Payroll posting is not automated in Stage 9B." icon="i-lucide-calendar-range"><template #actions><UInput v-model="year" type="number" class="w-28"/><UInput v-model="month" type="number" class="w-24"/><UButton label="Recalculate" :loading="loading" @click="recalc"/><UButton label="Refresh" variant="subtle" :loading="loading" @click="refresh"/></template></UiModulePageHeader><div class="grid gap-3 md:grid-cols-5"><UCard><p class="text-xs text-muted">Present</p><strong>{{ data?.presentDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Late</p><strong>{{ data?.lateDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Half Day</p><strong>{{ data?.halfDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">Absent</p><strong>{{ data?.absentDays || 0 }}</strong></UCard><UCard><p class="text-xs text-muted">OT Minutes</p><strong>{{ data?.overtimeMinutes || 0 }}</strong></UCard></div><AttendanceMonthlyGrid :rows="data?.days || []" /></section></AppShell></template>
